# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration platform that coordinates multiple
team members (agents/users) working together on shared projects.  It models
the kind of cooperative planning and execution described in the task brief:
distinct participants with roles, a shared communication channel (messages
and attachments), coordinated work allocation (tasks and assignments), and
observable outcomes over time (performance dashboards and exportable
reports).

The public surface is intentionally small and explicit:

* ``TeamCollaborationManager`` is the orchestrator.  It owns a single shared
  lock and exposes domain operations through cohesive service objects
  (``users``, ``projects``, ``tasks``, ``messages``, ``performance`` and
  ``reports``) that all serialize through that one lock.
* Every getter returns a deep copy so callers can never mutate internal
  state by accident.
* Identifiers are globally unique and monotonically increasing across every
  entity type.

Standard library only.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Roles a participant can hold."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle states for a unit of work."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export encodings."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message.

    Only metadata is retained -- the raw bytes are measured for ``size`` and
    discarded so the store stays lightweight.
    """

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A participant in the collaboration space."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A bounded body of work owned by a single user."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""


@dataclass
class Task:
    """A single unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    """A communication posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """Peer feedback from one user about another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Shared context
# ---------------------------------------------------------------------------
class _Context:
    """Holds all mutable state plus the single shared lock.

    Every service operates on this context, which is how distinct services
    stay consistent with one another while still presenting cohesive APIs.
    """

    def __init__(self, now_fn: Callable[[], datetime]):
        self.lock = threading.RLock()
        self._now_fn = now_fn
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}
        self._next_id = 1

    # -- time -----------------------------------------------------------
    def now(self) -> datetime:
        return self._now_fn()

    # -- identifiers ----------------------------------------------------
    def next_id(self) -> int:
        with self.lock:
            value = self._next_id
            self._next_id += 1
            return value

    # -- isolation ------------------------------------------------------
    @staticmethod
    def clone(obj):
        return copy.deepcopy(obj)

    # -- existence guards ----------------------------------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message


class _BaseService:
    """Common base giving every service the shared lock and context."""

    def __init__(self, ctx: _Context):
        self._ctx = ctx
        self._lock = ctx.lock


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class UserService(_BaseService):
    @staticmethod
    def _valid_email(email: str) -> bool:
        return bool(email) and "@" in email

    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if username is None or not username.strip():
                raise ValidationError("username is required")
            if email is None or not self._valid_email(email.strip()):
                raise ValidationError("a valid email is required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            uname = username.strip()
            mail = email.strip()
            for existing in self._ctx.users.values():
                if existing.username == uname:
                    raise DuplicateError("username already in use")
                if existing.email == mail:
                    raise DuplicateError("email already in use")

            user = User(
                id=self._ctx.next_id(),
                username=uname,
                email=mail,
                role=role,
                created_at=self._ctx.now(),
            )
            self._ctx.users[user.id] = user
            return self._ctx.clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return self._ctx.clone(self._ctx.require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            users = sorted(self._ctx.users.values(), key=lambda u: u.id)
            return [self._ctx.clone(u) for u in users]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._ctx.require_user(user_id)

            if username is not None:
                uname = username.strip()
                if not uname:
                    raise ValidationError("username is required")
                for other_id, other in self._ctx.users.items():
                    if other_id != user_id and other.username == uname:
                        raise DuplicateError("username already in use")

            if email is not None:
                mail = email.strip()
                if not self._valid_email(mail):
                    raise ValidationError("a valid email is required")
                for other_id, other in self._ctx.users.items():
                    if other_id != user_id and other.email == mail:
                        raise DuplicateError("email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username.strip()
            if email is not None:
                user.email = email.strip()
            if role is not None:
                user.role = role
            return self._ctx.clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            self._ctx.require_user(user_id)

            for project in self._ctx.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project and cannot be deleted")

            for task in self._ctx.tasks.values():
                if task.assignee_id == user_id and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks and cannot be deleted")

            del self._ctx.users[user_id]


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class ProjectService(_BaseService):
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            self._ctx.require_user(owner_id)
            if name is None or not name.strip():
                raise ValidationError("project name is required")
            if end_date < start_date:
                raise ValidationError("end date cannot precede start date")

            project = Project(
                id=self._ctx.next_id(),
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
            )
            self._ctx.projects[project.id] = project
            return self._ctx.clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self._ctx.clone(self._ctx.require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            projects = sorted(self._ctx.projects.values(), key=lambda p: p.id)
            return [self._ctx.clone(p) for p in projects]

    def update_project(self, project_id, name=None, start_date=None, end_date=None, description=None) -> Project:
        with self._lock:
            project = self._ctx.require_project(project_id)

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date

            if name is not None and not name.strip():
                raise ValidationError("project name is required")
            if new_end < new_start:
                raise ValidationError("end date cannot precede start date")

            if name is not None:
                project.name = name.strip()
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return self._ctx.clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._ctx.require_project(project_id)

            task_ids = {
                tid for tid, task in self._ctx.tasks.items()
                if task.project_id == project_id
            }
            for tid in task_ids:
                del self._ctx.tasks[tid]

            message_ids = [
                mid for mid, message in self._ctx.messages.items()
                if message.project_id == project_id or message.task_id in task_ids
            ]
            for mid in message_ids:
                del self._ctx.messages[mid]

            del self._ctx.projects[project_id]


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class TaskService(_BaseService):
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._ctx.require_project(project_id)
            if title is None or not title.strip():
                raise ValidationError("task title is required")
            if assignee_id is not None:
                self._ctx.require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task = Task(
                id=self._ctx.next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._ctx.now(),
            )
            self._ctx.tasks[task.id] = task
            return self._ctx.clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self._ctx.clone(self._ctx.require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._ctx.require_project(project_id)
            tasks = [
                t for t in self._ctx.tasks.values() if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [self._ctx.clone(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._ctx.require_user(assignee_id)
            tasks = [
                t for t in self._ctx.tasks.values() if t.assignee_id == assignee_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [self._ctx.clone(t) for t in tasks]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.require_user(assignee_id)
            task.assignee_id = assignee_id
            return self._ctx.clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.require_user(new_assignee_id)
            task.assignee_id = new_assignee_id
            return self._ctx.clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            task.assignee_id = None
            return self._ctx.clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if deadline is not None:
                project = self._ctx.require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return self._ctx.clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._ctx.now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return self._ctx.clone(task)


# ---------------------------------------------------------------------------
# Message service
# ---------------------------------------------------------------------------
class MessageService(_BaseService):
    @staticmethod
    def _build_attachments(items, uploaded_by, when) -> List[Attachment]:
        attachments = []
        for filename, data in items:
            attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploaded_by,
                    uploaded_at=when,
                )
            )
        return attachments

    def post_message(self, author_id, body, project_id=None, task_id=None, attachments=None, parent_id=None) -> Message:
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            self._ctx.require_user(author_id)
            if project_id is not None:
                self._ctx.require_project(project_id)
            else:
                self._ctx.require_task(task_id)
            if parent_id is not None:
                self._ctx.require_message(parent_id)

            items = list(attachments) if attachments else []
            if (body is None or not body.strip()) and not items:
                raise ValidationError("message body or an attachment is required")

            now = self._ctx.now()
            message = Message(
                id=self._ctx.next_id(),
                author_id=author_id,
                body=body or "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=self._build_attachments(items, author_id, now),
                created_at=now,
            )
            self._ctx.messages[message.id] = message
            return self._ctx.clone(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if new_body is None or not new_body.strip():
                raise ValidationError("message body is required")
            message.body = new_body
            message.edited_at = self._ctx.now()
            return self._ctx.clone(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may attach files")
            if filename is None or not filename.strip():
                raise ValidationError("filename is required")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._ctx.now(),
                )
            )
            return self._ctx.clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._ctx.require_project(project_id)
            messages = [
                m for m in self._ctx.messages.values() if m.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [self._ctx.clone(m) for m in messages]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._ctx.require_task(task_id)
            messages = [
                m for m in self._ctx.messages.values() if m.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [self._ctx.clone(m) for m in messages]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            del self._ctx.messages[message_id]


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class PerformanceService(_BaseService):
    def _tasks_for(self, user_id) -> List[Task]:
        return [t for t in self._ctx.tasks.values() if t.assignee_id == user_id]

    def _ratings_for(self, user_id) -> List[Rating]:
        return [r for r in self._ctx.ratings.values() if r.ratee_id == user_id]

    @staticmethod
    def _completion_rate(tasks) -> float:
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def _durations(tasks) -> List[float]:
        durations = []
        for t in tasks:
            if (
                t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ):
                durations.append((t.completed_at - t.started_at).total_seconds())
        return durations

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._ctx.require_user(user_id)
            return self._completion_rate(self._tasks_for(user_id))

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._ctx.require_user(user_id)
            durations = self._durations(self._tasks_for(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            self._ctx.require_user(rater_id)
            self._ctx.require_user(ratee_id)
            if isinstance(score, bool) or not isinstance(score, int) or not (1 <= score <= 5):
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None:
                self._ctx.require_task(task_id)

            rating = Rating(
                id=self._ctx.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._ctx.now(),
            )
            self._ctx.ratings[rating.id] = rating
            return self._ctx.clone(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            ratings = self._ratings_for(user_id)
            ratings.sort(key=lambda r: r.id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": [self._ctx.clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._tasks_for(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            durations = self._durations(tasks)
            avg_time = (sum(durations) / len(durations)) if durations else None

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
            ) if rating_count else 0.0

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Report service
# ---------------------------------------------------------------------------
class ReportService(_BaseService):
    def __init__(self, ctx: _Context, performance: PerformanceService):
        super().__init__(ctx)
        self._performance = performance

    def _user_row(self, user_id, tasks) -> dict:
        user = self._ctx.users.get(user_id)
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = PerformanceService._durations(tasks)
        avg_time = (sum(durations) / len(durations)) if durations else None
        ratings = self._performance._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count
        ) if rating_count else 0.0
        return {
            "user_id": user_id,
            "username": user.username if user is not None else None,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self._ctx.require_project(project_id)
            tasks = [
                t for t in self._ctx.tasks.values() if t.project_id == project_id
            ]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for t in tasks:
                status_counts[t.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._ctx.now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, dict] = {}
            for t in tasks:
                if t.assignee_id is None:
                    continue
                entry = per_assignee.setdefault(
                    t.assignee_id, {"total": 0, "completed": 0}
                )
                entry["total"] += 1
                if t.status == TaskStatus.COMPLETED:
                    entry["completed"] += 1
            for entry in per_assignee.values():
                entry["completion_rate"] = (
                    entry["completed"] / entry["total"]
                ) if entry["total"] else 0.0

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._ctx.require_project(project_id)
                tasks = [
                    t for t in self._ctx.tasks.values()
                    if t.project_id == project_id
                ]
            else:
                tasks = list(self._ctx.tasks.values())

            user_ids = sorted(
                {t.assignee_id for t in tasks if t.assignee_id is not None}
            )
            rows = [
                self._user_row(uid, [t for t in tasks if t.assignee_id == uid])
                for uid in user_ids
            ]

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            user = self._ctx.require_user(user_id)
            tasks = [
                t for t in self._ctx.tasks.values() if t.assignee_id == user_id
            ]
            tasks.sort(key=lambda t: t.id)

            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            durations = PerformanceService._durations(tasks)
            avg_time = (sum(durations) / len(durations)) if durations else None

            ratings = self._performance._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
            ) if rating_count else 0.0

            task_rows = [
                {
                    "id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "assignee_id": t.assignee_id,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    # -- export ---------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if report_format == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    @staticmethod
    def _to_csv(report) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            columns = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in columns])

        elif report_type == ReportType.PROJECT_PROGRESS.value:
            counts = report.get("status_counts", {})
            writer.writerow([
                "project_id", "total_tasks", "not_started",
                "in_progress", "completed", "completion_rate", "overdue_tasks",
            ])
            writer.writerow([
                report.get("project_id", ""),
                report.get("total_tasks", 0),
                counts.get(TaskStatus.NOT_STARTED.value, 0),
                counts.get(TaskStatus.IN_PROGRESS.value, 0),
                counts.get(TaskStatus.COMPLETED.value, 0),
                report.get("completion_rate", 0.0),
                report.get("overdue_tasks", 0),
            ])

        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            columns = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "in_progress_tasks", "not_started_tasks", "completion_rate",
                "average_completion_time", "rating_count", "rating_average",
            ]
            writer.writerow(columns)
            writer.writerow([report.get(col, "") for col in columns])

        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, value])

        return output.getvalue()

    def _to_pdf(self, report) -> bytes:
        lines = ["Report: {0}".format(report.get("report_type", "unknown"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, value)[:200])
        return self._build_pdf(lines)

    @staticmethod
    def _escape_pdf_text(text) -> str:
        return (
            str(text)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    @classmethod
    def _build_pdf(cls, lines) -> bytes:
        text_ops = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
        for index, line in enumerate(lines):
            if index:
                text_ops.append("T*")
            text_ops.append("({0}) Tj".format(cls._escape_pdf_text(line)))
        text_ops.append("ET")
        content = "\n".join(text_ops).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
            b"<< /Length " + str(len(content)).encode("ascii") + b" >>\n"
            b"stream\n" + content + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(number).encode("ascii")
            pdf += body
            pdf += b"\nendobj\n"

        xref_position = len(pdf)
        size = len(objects) + 1
        pdf += "xref\n0 {0}\n".format(size).encode("ascii")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("ascii")
        pdf += b"startxref\n"
        pdf += "{0}\n".format(xref_position).encode("ascii")
        pdf += b"%%EOF"
        return bytes(pdf)


