class TeamCollaborationManager:
    """Facade coordinating every collaboration service behind one lock."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        now_fn = now if now is not None else datetime.now
        self._ctx = _Context(now_fn)
        self._lock = self._ctx.lock

        # Cohesive services, all sharing the single lock and context.
        self.users = UserService(self._ctx)
        self.projects = ProjectService(self._ctx)
        self.tasks = TaskService(self._ctx)
        self.messages = MessageService(self._ctx)
        self.performance = PerformanceService(self._ctx)
        self.reports = ReportService(self._ctx, self.performance)

        self._wire_facade()

    def _wire_facade(self) -> None:
        # Users
        self.register_user = self.users.register_user
        self.get_user = self.users.get_user
        self.list_users = self.users.list_users
        self.update_user = self.users.update_user
        self.delete_user = self.users.delete_user

        # Projects
        self.create_project = self.projects.create_project
        self.get_project = self.projects.get_project
        self.list_projects = self.projects.list_projects
        self.update_project = self.projects.update_project
        self.delete_project = self.projects.delete_project

        # Tasks
        self.create_task = self.tasks.create_task
        self.get_task = self.tasks.get_task
        self.list_tasks_by_project = self.tasks.list_tasks_by_project
        self.list_tasks_by_assignee = self.tasks.list_tasks_by_assignee
        self.assign_task = self.tasks.assign_task
        self.reassign_task = self.tasks.reassign_task
        self.unassign_task = self.tasks.unassign_task
        self.set_deadline = self.tasks.set_deadline
        self.update_status = self.tasks.update_status

        # Messages
        self.post_message = self.messages.post_message
        self.edit_message = self.messages.edit_message
        self.add_attachment = self.messages.add_attachment
        self.list_messages_by_project = self.messages.list_messages_by_project
        self.list_messages_by_task = self.messages.list_messages_by_task
        self.delete_message = self.messages.delete_message

        # Performance
        self.get_completion_rate = self.performance.get_completion_rate
        self.get_average_completion_time = self.performance.get_average_completion_time
        self.submit_rating = self.performance.submit_rating
        self.get_ratings_summary = self.performance.get_ratings_summary
        self.get_user_dashboard = self.performance.get_user_dashboard

        # Reports
        self.project_progress_report = self.reports.project_progress_report
        self.team_performance_report = self.reports.team_performance_report
        self.individual_performance_report = self.reports.individual_performance_report
        self.export_report = self.reports.export_report


